#include<bits/stdc++.h>
#define ll long long
using namespace std;
const int MAXM=1e5+5,MAXN=1e3+5; 
struct node{int x,y,time;}a[MAXM];int n,m,fa[MAXN];
bool cmp(node x,node y){return x.time<y.time;}
int find(int x){return ((fa[x]==x)?(x):(fa[x]=find(fa[x])));}
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%d%d",&n,&m);
	for(int i=1;i<=m;++i)scanf("%d%d%d",&(a[i].x),&(a[i].y),&(a[i].time));
	sort(a+1,a+m+1,cmp);
	for(int i=1;i<=n;++i)fa[i]=i;
	for(int i=1;i<=m;++i){
		int fax=find(a[i].x),fay=find(a[i].y);
		if(fax!=fay){fa[fax]=fay;n--;}
		if(n==1){printf("%d ",a[i].time);return false;}
	}printf("-1");
	return false;
}
